"""Shared scaffolding between sync `Run` and async `AsyncRun`.

Holds the run identity, status, terminal-result cache, listener registry,
and the pure state-mutation logic that's identical between sync and
async. Subclasses provide stream iteration (`_events` / `__iter__` vs
`__aiter__`) and per-event callback dispatch (sync invocation vs `await
_maybe_await`). The two callers used to carry byte-identical copies of
`_capture_ids`, `_set_status`, `_apply_result`, the constructor body,
and the bulk of `_handle_event`, every one of which had to stay in
sync by reviewer vigilance — this module collapses them into one source
of truth.
"""

from __future__ import annotations

import warnings
from collections.abc import Callable
from dataclasses import replace
from typing import Any, Mapping

from .types import (
    RunResult,
    RunSnapshot,
    RunStreamEvent,
    SDKMessage,
    SDKUsageMessage,
    SendOptions,
    TokenUsage,
    normalize_run_status,
    sum_token_usage,
)

# Zero-arg thunk that performs one user-callback invocation. Sync callers
# invoke it directly; async callers `await _maybe_await(thunk())`. Wrapping
# every callback (on_delta, on_step, on_did_change_status listeners) in a
# thunk lets all three flow through the same deferred-dispatch mechanism
# regardless of their signatures (dict arg vs string arg) and lets the
# async path await any awaitable they return.
_EventCallback = Callable[[], Any]
_TERMINAL_RUN_STATUSES = {"finished", "error", "cancelled", "expired"}


class _RunBase:
    """State + state-mutation logic shared between `Run` and `AsyncRun`.

    Construction takes either a snapshot (for `get_run` / `list_runs`)
    or just identity fields (used by stream-attaching factories on the
    subclasses). Stream wiring (`_event_stream`, priming) lives on the
    subclasses because sync primes in `__init__` while async needs an
    awaited factory method.
    """

    # Set by Agent.send / AsyncRun._from_stream to the parent agent's
    # api_key so agent-scoped RPCs forward it. Run-scoped RPCs intentionally
    # don't consume this — see `_client._is_cloud_agent_rpc`.
    _api_key: str = ""

    def __init__(
        self,
        *,
        client: Any,
        run_id: str = "",
        agent_id: str = "",
        snapshot: RunSnapshot | None = None,
        send_options: SendOptions | None = None,
    ) -> None:
        self.client = client
        self.id = snapshot.id if snapshot else run_id
        self.agent_id = snapshot.agent_id if snapshot else agent_id
        self.status = snapshot.status if snapshot else "running"
        self.result = snapshot.result if snapshot else ""
        self.model = snapshot.model if snapshot else None
        self.duration_ms = snapshot.duration_ms if snapshot else 0
        self.git = snapshot.git if snapshot else None
        self.created_at = snapshot.created_at if snapshot else None
        self._buffer: list[RunStreamEvent] = []
        self._terminal_result: RunResult | None = None
        self._send_options = send_options
        self._status_listeners: list[Callable[[str], None]] = []
        # Snapshot usage is cumulative metadata, not a per-turn stream entry.
        self._snapshot_usage: TokenUsage | None = (
            snapshot.usage if snapshot is not None else None
        )
        self._turn_usages: list[TokenUsage] = []

    @property
    def usage(self) -> TokenUsage | None:
        """Cumulative token usage across turns that reported it, or ``None``."""
        accumulated = sum_token_usage(self._turn_usages)
        if accumulated is not None:
            return accumulated
        if (
            self._terminal_result is not None
            and self._terminal_result.usage is not None
        ):
            return self._terminal_result.usage
        return self._snapshot_usage

    @property
    def run_id(self) -> str:
        """Deprecated. Use `Run.id` instead."""
        warnings.warn(
            "Run.run_id is deprecated; use Run.id instead",
            DeprecationWarning,
            stacklevel=2,
        )
        return self.id

    @run_id.setter
    def run_id(self, value: str) -> None:
        warnings.warn(
            "Run.run_id is deprecated; assign to Run.id instead",
            DeprecationWarning,
            stacklevel=2,
        )
        self.id = value

    def supports(self, operation: str) -> bool:
        return operation in {"stream", "wait", "cancel", "conversation"}

    def unsupported_reason(self, operation: str) -> str | None:
        if self.supports(operation):
            return None
        return f"Run operation {operation!r} is not supported"

    unsupportedReason = unsupported_reason

    def on_did_change_status(
        self, listener: Callable[[str], None]
    ) -> Callable[[], None]:
        self._status_listeners.append(listener)

        def dispose() -> None:
            try:
                self._status_listeners.remove(listener)
            except ValueError:
                pass

        return dispose

    def _capture_ids(self, message: SDKMessage) -> None:
        agent_id = getattr(message, "agent_id", "")
        run_id = getattr(message, "run_id", "")
        if agent_id:
            self.agent_id = agent_id
        if run_id:
            self.id = run_id

    def _apply_result(self, result: RunResult) -> list[_EventCallback]:
        """Apply a terminal `RunResult` to this run's state and return any
        status-listener thunks the caller must dispatch. Like
        `_set_status`, the listener calls are deferred so async callers
        can await listeners that return coroutines.
        """
        self.id = result.id or self.id
        self.agent_id = result.agent_id or self.agent_id
        self.result = result.result
        self.model = result.model
        self.duration_ms = result.duration_ms
        self.git = result.git
        self.created_at = result.created_at
        if result.usage is not None and not self._turn_usages:
            self._turn_usages.append(result.usage)
        return self._set_status(result.status)

    def _set_status(self, status: str) -> list[_EventCallback]:
        """Mutate `self.status` and return one zero-arg thunk per
        registered listener. The caller invokes them: sync via direct
        call, async via `await _maybe_await(thunk())`. Returning the
        thunks instead of calling listeners inline is what lets async
        users register awaitable listeners — see Bugbot
        `9d240b43-b9f9-49c3-913f-41499210a4c7`.
        """
        if status == self.status:
            return []
        self.status = status
        # Snapshot at call time: a listener may dispose itself, so iterate
        # over a copy. Default args bind `listener` and `status` per
        # iteration to avoid the closure-over-loop-variable pitfall.
        return [
            (lambda cb=listener, s=status: cb(s))
            for listener in list(self._status_listeners)
        ]

    def _apply_event_state(self, event: RunStreamEvent) -> list[_EventCallback]:
        """Apply state mutations from one stream event and return the
        user callbacks (as zero-arg thunks) the caller must dispatch.

        Sync `Run._handle_event` invokes each thunk directly. Async
        `AsyncRun._handle_event` awaits each one through `_maybe_await`.
        This is the only difference between the two paths; everything
        else — id capture, status updates, terminal result handling —
        is identical and lives here.
        """
        callbacks: list[_EventCallback] = []
        send_options = self._send_options
        if event.sdk_message is not None:
            self._capture_ids(event.sdk_message)
            if isinstance(event.sdk_message, SDKUsageMessage):
                self._turn_usages.append(event.sdk_message.usage)
            if getattr(event.sdk_message, "type", "") == "status":
                status = getattr(event.sdk_message, "status", "")
                callbacks.extend(self._set_status(normalize_run_status(str(status))))
        if (
            event.interaction_update is not None
            and send_options is not None
            and send_options.on_delta is not None
        ):
            on_delta = send_options.on_delta
            update = event.interaction_update
            callbacks.append(lambda: on_delta(update))
        if (
            event.step is not None
            and send_options is not None
            and send_options.on_step is not None
        ):
            on_step = send_options.on_step
            step = event.step
            callbacks.append(lambda: on_step(step))
        if event.result is not None:
            result_payload: Mapping[str, Any] = {
                **event.result,
                "runId": event.result.get("runId") or self.id,
                "agentId": event.result.get("agentId") or self.agent_id,
            }
            if event.result_is_full:
                result = RunResult.from_json(result_payload)
                callbacks.extend(self._apply_result(result))
                self._terminal_result = result
            else:
                self.id = str(result_payload.get("runId") or self.id)
                self.agent_id = str(result_payload.get("agentId") or self.agent_id)
                callbacks.extend(
                    self._set_status(
                        normalize_run_status(str(result_payload.get("status", "")))
                    )
                )
        return callbacks

    def _result_with_accumulated_usage(self, result: RunResult) -> RunResult:
        """Prefer stream-turn usage; else keep snapshot if the wire result omitted it."""
        accumulated = sum_token_usage(self._turn_usages)
        preferred = accumulated
        if preferred is None and result.usage is None:
            preferred = self._snapshot_usage
        if preferred is None or result.usage == preferred:
            return result
        enriched = replace(result, usage=preferred)
        self._terminal_result = enriched
        return enriched
